+            var self = this;
+            if (typeof port === 'object') {
+                var options = port;
+                port = options.port;
+                address = options.address;
+                callback = address;
+            }
+            if (typeof address === 'function') {
+                callback = address;
+                address = '0.0.0.0';
+            }
+
+            this._port = port || 0;
+            this._address = address || '0.0.0.0';
+
+            if (callback) this.once('listening', callback);
